CREATE TABLE IF NOT EXISTS public.whatsapp_conversations ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW() ); CREATE TABLE IF NOT EXISTS public.whatsapp_messages ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), conversation_id UUID REFERENCES public.whatsapp_conversations(id) ON DELETE CASCADE, sender_role TEXT, content TEXT, created_at TIMESTAMPTZ DEFAULT NOW() );
